import React, { useState, useEffect, useRef } from 'react';
import { slotAPI } from '../services/api';
import io from 'socket.io-client';

const SlotManagementPage = () => {
  const [slots, setSlots] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [successMessage, setSuccessMessage] = useState('');
  const [showForm, setShowForm] = useState(false);
  const [formData, setFormData] = useState({
    date: '',
    time: '',
    duration: 30,
    topic: '',
  });
  const socketRef = useRef(null);

  useEffect(() => {
    fetchSlots();
  }, []);

  useEffect(() => {
    socketRef.current = io('http://localhost:5000', {
      auth: {
        token: sessionStorage.getItem('token') || localStorage.getItem('token'),
      },
    });

    socketRef.current.on('slot_updated', () => {
      fetchSlots();
    });

    return () => {
      socketRef.current.off('slot_updated');
      socketRef.current.disconnect();
    };
  }, []);

  const fetchSlots = async () => {
    setLoading(true);
    setError('');
    try {
      const res = await slotAPI.getMySlots();
      setSlots(res.data.slots || []);
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to fetch slots');
    } finally {
      setLoading(false);
    }
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: name === 'duration' ? parseInt(value, 10) : value,
    }));
  };

  const handleCreateSlot = async (e) => {
    e.preventDefault();
    setError('');
    try {
      await slotAPI.createSlot(formData);
      setSuccessMessage('Slot created successfully.');
      setTimeout(() => setSuccessMessage(''), 3000);
      setFormData({ date: '', time: '', duration: 30, topic: '' });
      setShowForm(false);
      fetchSlots();
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to create slot');
    }
  };

  const handleDeleteSlot = async (slotId) => {
    if (!window.confirm('Delete this slot?')) return;

    try {
      await slotAPI.deleteSlot(slotId);
      setSuccessMessage('Slot deleted successfully.');
      setTimeout(() => setSuccessMessage(''), 3000);
      fetchSlots();
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to delete slot');
    }
  };

  const formatDateTime = (date, time) => {
    try {
      return `${new Date(date).toLocaleDateString()} at ${time}`;
    } catch {
      return `${date} at ${time}`;
    }
  };

  const isSlotFinished = (dateStr, timeStr, durationMinutes) => {
    if (!dateStr || !timeStr) return false;
    try {
      // Create a Date object from the date string.
      // We assume dateStr is in a format like 'YYYY-MM-DD' and timeStr is 'HH:mm'
      // To ensure local time timezone correctly, we parse it manually if needed, 
      // but standard template string works in most modern browsers:
      const slotStart = new Date(`${dateStr.split('T')[0]}T${timeStr}`);
      if (isNaN(slotStart.getTime())) return false;

      const slotEnd = new Date(slotStart.getTime() + (durationMinutes || 30) * 60000);
      return new Date() > slotEnd;
    } catch {
      return false;
    }
  };

  return (
    <>
      <div className="animated-bg">
        <div className="blob blob-1"></div>
        <div className="blob blob-2"></div>
        <div className="blob blob-3"></div>
      </div>
      <div className="page-content">
        <div className="dashboard-header mb-4">
          <span className="nav-unread" style={{ background: 'var(--accent-light)', color: 'var(--accent-primary)', padding: '4px 12px' }}>Sessions</span>
          <h1 className="dashboard-title">Slot Management</h1>
          <p className="dashboard-subtitle">
            Publish your availability, review booking status, and keep upcoming sessions organized.
          </p>
        </div>

        {error && (
          <div style={{ background: 'rgba(239, 68, 68, 0.2)', border: '1px solid var(--status-danger)', padding: '1rem', borderRadius: '12px', marginBottom: '1rem', display: 'flex', justifyContent: 'space-between' }}>
            <span>{error}</span>
            <button onClick={() => setError('')} style={{ color: 'white' }}>x</button>
          </div>
        )}

        {successMessage && (
          <div style={{ background: 'rgba(34, 197, 94, 0.2)', border: '1px solid var(--status-success)', padding: '1rem', borderRadius: '12px', marginBottom: '1rem', display: 'flex', justifyContent: 'space-between' }}>
            <span>{successMessage}</span>
            <button onClick={() => setSuccessMessage('')} style={{ color: 'white' }}>x</button>
          </div>
        )}

        <div className="floating-grid" style={{ marginBottom: '2rem' }}>
          <div className="island-card">
            <div style={{ fontSize: '0.85rem', color: 'var(--text-muted)', fontWeight: 'bold', textTransform: 'uppercase', marginBottom: '0.5rem' }}>Total Slots</div>
            <div style={{ fontSize: '2.5rem', fontWeight: 'bold', color: 'var(--text-main)' }}>{slots.length}</div>
          </div>
          <div className="island-card">
            <div style={{ fontSize: '0.85rem', color: 'var(--text-muted)', fontWeight: 'bold', textTransform: 'uppercase', marginBottom: '0.5rem' }}>Booked</div>
            <div style={{ fontSize: '2.5rem', fontWeight: 'bold', color: 'var(--accent-primary)' }}>{slots.filter((slot) => slot.status === 'Booked').length}</div>
          </div>
          <div className="island-card">
            <div style={{ fontSize: '0.85rem', color: 'var(--text-muted)', fontWeight: 'bold', textTransform: 'uppercase', marginBottom: '0.5rem' }}>Available</div>
            <div style={{ fontSize: '2.5rem', fontWeight: 'bold', color: 'var(--status-success)' }}>{slots.filter((slot) => slot.status !== 'Booked').length}</div>
          </div>
        </div>

        <div className="island-card" style={{ marginBottom: '2rem', display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '1rem' }}>
          <div>
            <div style={{ fontSize: '1.2rem', fontWeight: 'bold', color: 'var(--text-main)' }}>Action</div>
            <div style={{ color: 'var(--text-muted)' }}>Create and maintain your schedule</div>
          </div>
          <button className="btn btn-primary" style={{ padding: '0.5rem 1.5rem', borderRadius: '999px' }} onClick={() => setShowForm(!showForm)}>
            {showForm ? 'Close Form' : 'Create New Slot'}
          </button>
        </div>

        {showForm && (
          <div className="island-card" style={{ marginBottom: '2rem' }}>
            <h3 className="island-title mb-4">Create New Slot</h3>
            <form onSubmit={handleCreateSlot}>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem', marginBottom: '1.5rem' }}>
                <div>
                  <label htmlFor="date" style={{ display: 'block', marginBottom: '0.5rem', fontSize: '0.85rem', color: 'var(--text-muted)', fontWeight: 'bold' }}>Date</label>
                  <input type="date" className="form-input" style={{ width: '100%' }} id="date" name="date" value={formData.date} onChange={handleInputChange} required />
                </div>
                <div>
                  <label htmlFor="time" style={{ display: 'block', marginBottom: '0.5rem', fontSize: '0.85rem', color: 'var(--text-muted)', fontWeight: 'bold' }}>Time</label>
                  <input type="time" className="form-input" style={{ width: '100%' }} id="time" name="time" value={formData.time} onChange={handleInputChange} required />
                </div>
                <div>
                  <label htmlFor="duration" style={{ display: 'block', marginBottom: '0.5rem', fontSize: '0.85rem', color: 'var(--text-muted)', fontWeight: 'bold' }}>Duration (minutes)</label>
                  <input type="number" className="form-input" style={{ width: '100%' }} id="duration" name="duration" value={formData.duration} onChange={handleInputChange} min="15" max="120" step="15" />
                </div>
                <div>
                  <label htmlFor="topic" style={{ display: 'block', marginBottom: '0.5rem', fontSize: '0.85rem', color: 'var(--text-muted)', fontWeight: 'bold' }}>Topic</label>
                  <input type="text" className="form-input" style={{ width: '100%' }} id="topic" name="topic" value={formData.topic} onChange={handleInputChange} placeholder="Optional session topic" />
                </div>
              </div>
              <button type="submit" className="btn btn-primary" style={{ width: '100%' }}>Create Slot</button>
            </form>
          </div>
        )}

        {loading ? (
          <div style={{ padding: '3rem', textAlign: 'center', color: 'var(--text-muted)' }}>
            <span>Loading...</span>
          </div>
        ) : slots.length === 0 ? (
          <div className="island-card" style={{ padding: '3rem', textAlign: 'center' }}>
            <div style={{ color: 'var(--text-muted)' }}>No slots created yet.</div>
          </div>
        ) : (
          <div className="island-card">
            <h3 className="island-title mb-4">Your Slots</h3>
            <div style={{ overflowX: 'auto' }}>
              <table style={{ width: '100%', minWidth: '600px', borderCollapse: 'collapse' }}>
                <thead>
                  <tr style={{ borderBottom: '1px solid rgba(255,255,255,0.1)', color: 'var(--text-muted)', textAlign: 'left', fontSize: '0.85rem', textTransform: 'uppercase' }}>
                    <th style={{ padding: '1rem', fontWeight: 'bold' }}>Date & Time</th>
                    <th style={{ padding: '1rem', fontWeight: 'bold' }}>Duration</th>
                    <th style={{ padding: '1rem', fontWeight: 'bold' }}>Topic</th>
                    <th style={{ padding: '1rem', fontWeight: 'bold' }}>Status</th>
                    <th style={{ padding: '1rem', fontWeight: 'bold' }}>Student</th>
                    <th style={{ padding: '1rem', fontWeight: 'bold', textAlign: 'right' }}>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {slots.map((slot) => (
                    <tr key={slot._id} style={{ borderBottom: '1px solid rgba(255,255,255,0.05)', transition: 'background 0.2s', ':hover': { background: 'rgba(255,255,255,0.02)' } }}>
                      <td style={{ padding: '1rem', fontWeight: 'bold' }}>{formatDateTime(slot.date, slot.time)}</td>
                      <td style={{ padding: '1rem' }}>{slot.duration} min</td>
                      <td style={{ padding: '1rem' }}>{slot.topic || 'Not specified'}</td>
                      <td style={{ padding: '1rem' }}>
                        <span style={{ 
                          padding: '0.25rem 0.75rem', 
                          borderRadius: '999px', 
                          fontSize: '0.85rem', 
                          fontWeight: 'bold',
                          background: isSlotFinished(slot.date, slot.time, slot.duration) ? 'rgba(255,255,255,0.1)' : slot.status === 'Booked' ? 'rgba(34, 197, 94, 0.2)' : 'var(--accent-light)',
                          color: isSlotFinished(slot.date, slot.time, slot.duration) ? 'var(--text-muted)' : slot.status === 'Booked' ? 'var(--status-success)' : 'var(--accent-primary)'
                        }}>
                          {isSlotFinished(slot.date, slot.time, slot.duration) ? 'Finished' : slot.status}
                        </span>
                      </td>
                      <td style={{ padding: '1rem' }}>{slot.studentId?.name || 'Unassigned'}</td>
                      <td style={{ padding: '1rem', textAlign: 'right' }}>
                        {isSlotFinished(slot.date, slot.time, slot.duration) ? (
                          <span style={{ color: 'var(--text-muted)', fontWeight: 'bold', fontSize: '0.85rem' }}>Finished</span>
                        ) : (
                          <button 
                            onClick={() => handleDeleteSlot(slot._id)}
                            style={{ border: 'none', background: 'rgba(239, 68, 68, 0.2)', color: 'var(--status-danger)', borderRadius: '8px', padding: '0.5rem 1rem', cursor: 'pointer', fontWeight: 'bold' }}
                          >
                            Delete
                          </button>
                        )}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </div>
    </>
  );
};

export default SlotManagementPage;
